// // This module implements a 4-bit barrel shifter that shifts the input A based on a 2-bit select signal S. When S = 00, it outputs A unchanged; when S = 01, it performs a right shift by one bit; when S = 10, it performs a left shift by one bit; and for S = 11, it outputs the two most significant bits of A.
module top_module(
    input [3:0] A,
    input [1:0] S,
    output [3:0] Y
);assign Y = (S == 2'b00) ? A :
               (S == 2'b01) ? {A[2:0], 1'b0} :
               (S == 2'b10) ? {1'b0, A[3:1]} :
                              A[1:0];

endmodule
